mapper.update:
UPDATE task 

	task_no = task_no 

		, task_description = #{taskDescription}



		, task_title = #{taskTitle}



		, due_date = #{dueDate}



		, worker_no = #{workerNo}



		, label_title = #{labelTitle}



		, priority = #{priority}



		, status_no = #{statusNo}



WHERE space_key = #{spaceKey}
AND task_no = #{taskNo}


UPDATE task
SET task_order = task_order + 1
WHERE status_no = #{statusNo}
AND task_order >= #{afterTaskOrder}
AND task_order < #{beforeTaskOrder}
AND #{afterTaskOrder} < #{beforeTaskOrder}
AND space_key = #{spaceKey}


UPDATE task
SET task_order = task_order - 1
WHERE status_no = #{statusNo}
AND task_order <= #{afterTaskOrder}
AND task_order > #{beforeTaskOrder}
AND #{beforeTaskOrder} < #{afterTaskOrder}
AND space_key = #{spaceKey}

UPDATE task
SET task_order = #{afterTaskOrder}
WHERE task_no = #{taskNo}
AND space_key = #{spaceKey}

mapper.select:
SELECT * 
FROM task 
WHERE space_key IN (SELECT space_key FROM space_members WHERE user_no = #{currentUserNo}) 

	AND (task_title LIKE '%' || #{searchKeyWord} || '%' OR (space_key || '-' || task_no) LIKE '%' || #{searchKeyWord} || '%') 



		AND worker_no = #{searchWorkerNo} 


		AND worker_no != #{searchWorkerNo} 




		AND creator_no = #{searchCreatorNo} 


		AND creator_no != #{searchCreatorNo} 




		AND status_no = #{searchStatusNo} 			


		AND status_no != #{searchStatusNo} 




		AND space_key = #{searchSpaceKey} 			


		AND space_key != #{searchSpaceKey} 




		AND priority = #{searchPriority} 


		AND priority != #{searchPriority} 




		AND due_date >= TO_DATE(#{searchDueDate}, 'YYYY-MM-DD')


		AND due_date <= TO_DATE(#{searchDueDate}, 'YYYY-MM-DD')


ORDER BY task_order ASC
